create extension if not exists pgcrypto;
create table if not exists organizations(id uuid primary key default gen_random_uuid(),name text not null,slug text unique not null,created_at timestamptz default now());
create table if not exists users(id uuid primary key default gen_random_uuid(),email text unique not null,name text not null,created_at timestamptz default now());
create table if not exists memberships(id uuid primary key default gen_random_uuid(),organization_id uuid references organizations on delete cascade,user_id uuid references users on delete cascade,role text not null,unique(organization_id,user_id));
create table if not exists projects(id uuid primary key default gen_random_uuid(),organization_id uuid references organizations on delete cascade,name text not null,repository_url text not null,default_branch text default 'main',created_at timestamptz default now());
create table if not exists scans(id uuid primary key default gen_random_uuid(),project_id uuid references projects on delete cascade,status text not null,commit_sha text,branch text,score int,started_at timestamptz default now(),completed_at timestamptz);
create table if not exists findings(id uuid primary key default gen_random_uuid(),scan_id uuid references scans on delete cascade,fingerprint text not null,rule_id text not null,title text not null,severity text not null,confidence real not null,category text not null,scanner text not null,file_path text,line int,status text default 'open',payload jsonb not null default '{}'::jsonb);
create index if not exists findings_scan_idx on findings(scan_id); create index if not exists findings_fingerprint_idx on findings(fingerprint);
create table if not exists assets(id uuid primary key default gen_random_uuid(),scan_id uuid references scans on delete cascade,external_id text not null,type text not null,name text not null,exposure text not null,criticality int not null,metadata jsonb not null default '{}'::jsonb);
create table if not exists relations(id uuid primary key default gen_random_uuid(),scan_id uuid references scans on delete cascade,source_external_id text not null,target_external_id text not null,kind text not null,evidence text);
create table if not exists attack_paths(id uuid primary key default gen_random_uuid(),scan_id uuid references scans on delete cascade,title text not null,score int not null,likelihood int not null,impact int not null,payload jsonb not null);
create table if not exists remediations(id uuid primary key default gen_random_uuid(),project_id uuid references projects on delete cascade,title text not null,status text default 'open',priority int not null,payload jsonb not null,created_at timestamptz default now());
create table if not exists audit_logs(id uuid primary key default gen_random_uuid(),organization_id uuid references organizations on delete cascade,actor_id uuid,event text not null,resource_type text,resource_id text,payload jsonb default '{}'::jsonb,created_at timestamptz default now());
